'use strict';
const http = require('node:http');
const fs = require('node:fs');
const path = require('node:path');
function handler(request, response) {
  if (request.url === '/api/health') { response.writeHead(200, {'content-type':'application/json'}); return response.end(JSON.stringify({ok:true,message:'{{PROJECT_NAME}} ready'})); }
  const requested = request.url === '/' ? 'index.html' : request.url.slice(1);
  if (!['index.html','style.css','app.js'].includes(requested)) { response.writeHead(404); return response.end('Not found'); }
  response.writeHead(200); response.end(fs.readFileSync(path.join(__dirname, 'public', requested)));
}
if (require.main === module) http.createServer(handler).listen(3000, '127.0.0.1');
module.exports = { handler };

